      spawnSpark(p.slateMesh.position.clone().setY(BELT_Y + 2), 0x8fe3ff, 12);
      flashTerminal(`explained ${p.data.ckpt} — it's the ${p.data.name}; drag it to the bay you think it matches`, true);
      teachOnce("explained", "Now you know what it is. Drag it to the ship square you think it matches — you'll find out if you're right when you dispatch.", 9000);
