  ud.coreMat.color.setHex(color);
  ud.coreMat.emissive.setHex(color);
  ud.coreMat.emissiveIntensity = 1.1 + heat * 1.7 + pulse * 0.8;
  ud.halo.material.color.setHex(color);
  ud.halo.material.opacity = 0.14 + heat * 0.28 + pulse * 0.18;
  ud.alarmRing.material.color.setHex(color);

