  // A bay holding a placed (not-yet-filed) block glows amber; once dispatched it goes green.
  let col = 0x35506a, op = 0.4, hint = "", hintCss = "#7cffb0", hintShow = false, emis = 0x000000;
  const occ = squareOccupant(p.idx);
  if (occ && occ.state === "online") { col = RING.online; op = 0.7; }
  else if (occ) { col = RING.working; op = 0.5 + 0.18 * Math.sin(t * 3); }   // placed, awaiting grade
  ud.edgeMat.color.setHex(col); ud.edgeMat.opacity = op; ud.frameMat.emissive.setHex(emis);
  if (hintShow && ud.hint.userData.text !== hint) setSlotHint(p, hint, hintCss);
  ud.hint.visible = hintShow;
  if (p.state === "online") {
    if (p.installT > 0) p.installT = Math.max(0, p.installT - dt);
    const anim = p.slateMesh?.userData.upgradeModel.userData.anim;
    if (anim?.type === "ring") anim.ring.rotation.y += dt * 0.8;
    else if (anim?.type === "dome") { anim.field.rotation.y += dt * 0.25; anim.orbit.rotation.z += dt * 0.6; }
  }
}

