    p.slotPos.set(slotXForLane(slotLanes[i]), SHIP_Y, SHIP_Z); p.slot.position.copy(p.slotPos);
    p.state = "broken"; p.placedIn = null; p.explained = false; p.fixT = 0; p.installT = 0; p.beltX = ENTRANCE_X;
  });

