847	
848	  // ---------- lifecycle: dispatch → fix → belt → explain → install ----------
849	  // Click a generic red dot → a subagent flies to it and fixes the NEXT pending
850	  // part (pulled from a shuffled queue, so the dot never tells you which block).
851	  function dispatchFromDot(jd) {
852	    if (!jd || jd.taken || !pendingQueue.length) return;
853	    const d = freeDrone(); if (!d) { flashTerminal("every subagent is busy — wait for one to return", false); return; }
854	    const p = parts[pendingQueue.shift()];
855	    const wasUrgent = jd.heat >= DOT_HOT;
856	    jd.taken = true; jd.group.visible = false;
857	    p.state = "working";
858	    d.busy = true; d.part = p; d.phase = "out"; d.flyProg = 0; d.weldAt = jd.pos.clone();
859	    spawnSpark(jd.pos.clone(), 0x6fe3ff, 12);
860	    updateSystems();
861	    if (wasUrgent) teachOnce("urgent-relief", "Good call — dispatching aged pips slows the launch-window drain before the belt floods.", 7000);
862	    teachOnce("dispatched", "Sent — the subagent's flying out to fix it. What it brings back rides up the belt, sealed.", 8000);
863	  }
864	  function partToBelt(p) {                 // subagent finished → slate rides the belt
865	    p.state = "onbelt"; p.explained = false; p.beltX = ENTRANCE_X;
866	    const upgrade = BUILD[p.data.upgrade]();
867	    const slate = buildSlate(upgrade);
868	    slate.userData.partIdx = p.idx;
869	    slate.position.set(ENTRANCE_X, BELT_Y, 2);
870	    scene.add(slate);
871	    p.slateMesh = slate;
872	    belted.push(p.idx);
873	    updateSystems();
874	    teachOnce("onbelt", "Here it comes on the belt, sealed and silent. Click it to run `entire checkpoint explain`.", 8500);
875	  }
876	
877	  // ---------- review (explain) ----------
878	  function flashTerminal(t, ok) { if (!termMsg) return; clearTimeout(msgTimer); termMsg.textContent = t; termMsg.classList.remove("show-ok", "show-err"); termMsg.classList.add(ok ? "show-ok" : "show-err"); msgTimer = setTimeout(() => termMsg.classList.remove("show-ok", "show-err"), 3600); }
